 1	import React, { FC } from 'react';
 2	
 3	import { AnnotationsModal } from '@kubevirt-utils/components/AnnotationsModal/AnnotationsModal';
 4	import { LabelsModal } from '@kubevirt-utils/components/LabelsModal/LabelsModal';
 5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 6	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 7	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 8	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
10	import { getName } from '@kubevirt-utils/resources/shared';
11	import {
12	  DescriptionList,
13	  Grid,
14	  PageSection,
15	  PageSectionVariants,
16	  Title,
17	} from '@patternfly/react-core';
18	
19	import { updateAnnotation, updateLabels } from '../details/utils/utils';
20	import { ConfigurationInnerTabProps } from '../utils/types';
21	
22	import MetadataTabAnnotations from './components/MetadataTabAnnotations/MetadataTabAnnotations';
23	import MetadataTabLabels from './components/MetadataTabLabels/MetadataTabLabels';
24	
25	const MetadataTab: FC<ConfigurationInnerTabProps> = ({ vm }) => {
26	  const { t } = useKubevirtTranslation();
27	  const { createModal } = useModal();
28	
29	  return (
30	    <PageSection variant={PageSectionVariants.light}>
31	      <Title headingLevel="h2">
32	        <SearchItem id="metadata">{t('Metadata')}</SearchItem>
33	      </Title>
34	      <Grid span={6}>
35	        <DescriptionList className="pf-v6-c-description-list">
36	          <VirtualMachineDescriptionItem
37	            bodyContent={t(
38	              'Map of string keys and values that can be used to organize and categorize (scope and select) objects. May match selectors of replication controllers and services. ',
39	            )}
40	            onEditClick={() =>
41	              createModal(({ isOpen, onClose }) => (
42	                <LabelsModal
43	                  isOpen={isOpen}
44	                  obj={vm}
45	                  onClose={onClose}
46	                  onLabelsSubmit={(labels) => updateLabels(vm, labels)}
47	                />
48	              ))
49	            }
50	            breadcrumb="VirtualMachine.metadata.labels"
51	            data-test-id={`${getName(vm)}-labels`}
52	            descriptionData={<MetadataTabLabels labels={vm?.metadata?.labels} />}
53	            descriptionHeader={<SearchItem id="labels">{t('Labels')}</SearchItem>}
54	            editOnTitleJustify
55	            isEdit
56	            isPopover
57	            moreInfoURL={documentationURL.LABELS}
58	            showEditOnTitle
59	          />
60	          <VirtualMachineDescriptionItem
61	            bodyContent={t(
62	              'Annotations is an unstructured key value map stored with a resource that may be set by external tools to store and retrieve arbitrary metadata. They are not queryable and should be preserved when modifying objects. ',
63	            )}
64	            onEditClick={() =>
65	              createModal(({ isOpen, onClose }) => (
66	                <AnnotationsModal
67	                  isOpen={isOpen}
68	                  obj={vm}
69	                  onClose={onClose}
70	                  onSubmit={(annotations) => updateAnnotation(vm, annotations)}
71	                />
72	              ))
73	            }
74	            breadcrumb="VirtualMachine.metadata.annotations"
75	            descriptionData={<MetadataTabAnnotations annotations={vm?.metadata?.annotations} />}
76	            descriptionHeader={<SearchItem id="metadata">{t('Annotations')}</SearchItem>}
77	            isEdit
78	            isPopover
79	            moreInfoURL={documentationURL.ANNOTATIONS}
80	          />
81	        </DescriptionList>
82	      </Grid>
83	    </PageSection>
84	  );
85	};
86	
87	export default MetadataTab;

